+        let mut request = FrankenFuse::encode_move_ext_response(7, 11, 22, 33, 0);
+        request[MOVE_EXT_DONOR_FD_OFFSET..MOVE_EXT_DONOR_FD_OFFSET + 4]
+            .copy_from_slice(&(-1_i32).to_ne_bytes());
